  var subjects = Array.isArray(item.subject) ? item.subject.join(", ") : (item.subject || "");
  var desc = stripTags(item.description || subjects || "");
  var link = "https://archive.org/metadata/" + encodeURIComponent(id);
  var cover = "https://archive.org/services/img/" + encodeURIComponent(id);
  data.push(pageData(link, cover, item.title || id, desc, item.year || "", "Internet Archive", "Video", subjects.split(",").slice(0, 2).join(", ")));
}
emitPage("main", data, "Archive TV & Movies");

